async function bindleftCommonSearchdropdown(ths, modulename, filtername) {
    debugger
    var vm = ths;
    let param = `reqForm=leftSearch`;

    try {
        const response = await DataService.GetleftSearchDropdownData(param);
        if (response.data != null) {
            const parsedData = {
                clientList: JSON.parse(response.data.clientList).data,
                projectList: JSON.parse(response.data.projectList).data,
                state: JSON.parse(response.data.state).data,
                statusType: JSON.parse(response.data.statusType).data,
                invoiceDurationList: JSON.parse(response.data.invoiceDurationList)
            };
            if (parsedData.clientList.length > 0) {
                vm.SearchSchema[2].listOptions = [];
                parsedData.clientList.forEach(item => {
                    if (item.Name && item.Id && typeof item.Id === 'string' && item.Id.trim() !== '') {
                        try {
                            const idValue = item.Id.split('^')[0];
                            vm.SearchSchema[2].listOptions.push({
                                name: item.Name,
                                value: idValue
                            });
                        } catch (error) {
                            console.error('Error splitting item.Id for', item, error);
                        }
                    }
                });

            }

            if (parsedData.statusType.length > 0) {
                vm.SearchSchema[9].listOptions = parsedData.statusType.map(item => ({
                    name: item.STATUS_NAME,
                    value: item.STATUS_ID
                }));
            }


            if (parsedData.projectList.length > 0) {
                vm.SearchSchema[10].listOptions = parsedData.projectList.map(item => ({
                    name: item.Name,
                    value: item.Id
                }));
            }

            if (parsedData.state.length > 0) {
                vm.SearchSchema[11].listOptions = parsedData.state.map(item => ({
                    name: item.STATE_NAME,
                    value: item.STATE_ID
                }));
            }


            if (parsedData.invoiceDurationList.length > 0) {
                vm.SearchSchema[12].listOptions = parsedData.invoiceDurationList.map(item => ({
                    name: item.Name,
                    value: item.Value
                }));
            }
        }
    } catch (error) {
        console.error('Error fetching dropdown data:', error);
    }
}


export default { buttons, SearchSchema, bindleftCommonSearchdropdown };